import { marked } from 'marked';
import DOMPurify from 'dompurify';
import { useMemo } from 'react';

const SAFE_TAGS = ['p', 'strong', 'em', 'a', 'code', 'pre', 'ul', 'ol', 'li', 'blockquote', 'br'];
const SAFE_ATTR = ['href'];

DOMPurify.addHook('afterSanitizeAttributes', (node) => {
  if (node.nodeName === 'A' && node instanceof HTMLAnchorElement) {
    const href = node.getAttribute('href') ?? '';
    if (/^https?:\/\//i.test(href)) {
      node.setAttribute('target', '_blank');
      node.setAttribute('rel', 'noopener noreferrer');
    } else if (!href.startsWith('/') && !href.startsWith('#')) {
      node.removeAttribute('href');  // strip non-http/relative
    }
  }
});

export function Comment({ markdown }: { markdown: string }) {
  const html = useMemo(() => {
    const raw = marked.parse(markdown, { async: false }) as string;
    return DOMPurify.sanitize(raw, { ALLOWED_TAGS: SAFE_TAGS, ALLOWED_ATTR: SAFE_ATTR });
  }, [markdown]);
  return <div dangerouslySetInnerHTML={{ __html: html }} />;
}

