function Dashboard() {
  const user = useUser();
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);

  if (!mounted) {
    // Render placeholder during SSR + first paint
    return <div><h1>Welcome</h1><Skeleton /></div>;
  }

  return (
    <div>
      <h1>Welcome, {user?.name ?? 'Guest'}</h1>
      {user ? <UserContent user={user} /> : <GuestView />}
    </div>
  );
}

