function DebugPanel() {
  const storeState = useStore();  // hook first

  if (!import.meta.env.DEV) return null;

  return (
    <div className="fixed bottom-0 left-0 bg-yellow-100 text-xs p-2 max-w-md max-h-48 overflow-auto">
      <pre>{JSON.stringify(storeState, null, 2).slice(0, 500)}</pre>
    </div>
  );
}
// In Vite, import.meta.env.DEV is statically replaced. Tree-shakes in prod.
